SELECT * FROM notifications
WHERE recipient_id = #{recipientId}
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT * FROM notifications
WHERE recipient_id = #{recipientId}
  AND created_at > #{since}
ORDER BY created_at DESC

SELECT COUNT(*) FROM notifications
WHERE recipient_id = #{recipientId}
  AND is_read = 0

SELECT * FROM notifications
WHERE recipient_id = #{recipientId}
  AND is_read = 1
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM notifications
WHERE recipient_id = #{recipientId}
  AND is_read = 1

SELECT * FROM notifications
WHERE recipient_id = #{recipientId}
  AND is_read = 0
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

